package worker

import (
	"fmt"
	"log"
	"net/http"
)

var client = http.DefaultClient

func ProcessItems(items []string) {
	for _, item := range items {
		go func() {
			resp, err := client.Get(fmt.Sprintf("https://api.example.com/process/%s", item))
			if err != nil {
				log.Printf("failed to process %s: %v", item, err)
				return
			}
			defer resp.Body.Close()
			log.Printf("processed %s: status %d", item, resp.StatusCode)
		}()
	}
}
