func (s *PaymentService) Charge(ctx context.Context, req ChargeRequest) (*Receipt, error) {
	s.logger.Info("charging", "card", req.CardNumber, "amount", req.AmountCents, "user", req.UserID)
	receipt, err := s.gateway.Charge(ctx, req)
	if err != nil {
		s.logger.Error("charge failed", "err", err, "card", req.CardNumber)
		return nil, fmt.Errorf("charge: %w", err)
	}
	s.logger.Info("charge succeeded", "receipt_id", receipt.ID)
	return receipt, nil
}
